#ENC BY GHOST👻 

import zlib,base64,hmac,hashlib
def _pbkdf2(pw,salt,its=100000):
    return hashlib.pbkdf2_hmac("sha256", pw.encode(), salt, its, dklen=32)
def _keystream(key,n):
    out=b"";blk=0
    while len(out)<n:
        ctr=blk.to_bytes(8,"big")
        out+=hmac.new(key,ctr,hashlib.sha256).digest()
        blk+=1
    return out[:n]
def _xor(data,key):
    ks=_keystream(key,len(data))
    return bytes(a^b for a,b in zip(data,ks))
